function u(t){if(t===0)return"0 B";const o=1024,i=["B","KB","MB","GB","TB"],e=Math.floor(Math.log(t)/Math.log(o));return`${parseFloat((t/Math.pow(o,e)).toFixed(1))} ${i[e]}`}function f(t){if(!t)return"—";const o=new Date(t);if(isNaN(o.getTime()))return"—";const e=new Date().getTime()-o.getTime(),s=Math.floor(e/1e3),n=Math.floor(s/60),r=Math.floor(n/60),a=Math.floor(r/24);return s<60?"just now":n<60?`${n} minute${n!==1?"s":""} ago`:r<24?`${r} hour${r!==1?"s":""} ago`:a<7?`${a} day${a!==1?"s":""} ago`:o.toLocaleDateString("en-US",{year:"numeric",month:"short",day:"numeric"})}function c(t){if(!t)return"—";const o=new Date(t);return isNaN(o.getTime())?"—":o.toLocaleDateString("en-US",{year:"numeric",month:"short",day:"numeric",hour:"2-digit",minute:"2-digit"})}export{f as a,c as b,u as f};
